# Side scroller world, reinterpreted in 3D.
# Walk north (+z) from spawn: floating ? blocks, brick rows, green pipes,
# pits to jump over, a coin-block ceiling, the iconic staircase, flagpole
# and end-of-level castle.

(player x=0 y=1.8 z=-50 yaw=0)

# === Sky-blue ground border (far away, just so the horizon isn't empty) ===
# (the engine sky handles the rest)

# === Main grass ground strip, 14m wide × 120m long ===
(box x=0 y=-0.25 z=0 sx=14 sy=0.5 sz=120 mat='grass_01')

# === Pit 1 (carve straight through the ground; dirt floor underneath) ===
(sub (box x=0 y=-1 z=-12 sx=14 sy=2.5 sz=4 mat='grass_01'))
(box x=0 y=-2.75 z=-12 sx=14 sy=0.5 sz=4 mat='dirt_01')

# === Pit 2 (a wider double-gap) ===
(sub (box x=0 y=-1 z=14 sx=14 sy=2.5 sz=5 mat='grass_01'))
(box x=0 y=-2.75 z=14 sx=14 sy=0.5 sz=5 mat='dirt_01')

# === Pit 3 (just before the end-of-level run) ===
(sub (box x=0 y=-1 z=35 sx=14 sy=2.5 sz=4 mat='grass_01'))
(box x=0 y=-2.75 z=35 sx=14 sy=0.5 sz=4 mat='dirt_01')

# === First ? block (sitting alone above the spawn approach) ===
(box x=0 y=3 z=-42 sx=1 sy=1 sz=1 mat='sand_01')

# === Brick + ? block row #1 (the classic alternating row) ===
(box x=-1.5 y=3 z=-35 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-0.5 y=3 z=-35 sx=1 sy=1 sz=1 mat='sand_01')
(box x=0.5 y=3 z=-35 sx=1 sy=1 sz=1 mat='brick_02')
(box x=1.5 y=3 z=-35 sx=1 sy=1 sz=1 mat='sand_01')
# A single ? block above the row (the secret 1-up spot)
(box x=-0.5 y=6 z=-35 sx=1 sy=1 sz=1 mat='sand_01')


# === Pipe 1 — short green pipe ===
(cylinder x=0 y=1 z=-26 sx=2 sy=2 sz=2 mat='grass_01')
(cylinder x=0 y=2.15 z=-26 sx=2.4 sy=0.3 sz=2.4 mat='grass_01')

# === Pipe 2 — medium ===
(cylinder x=0 y=1.5 z=-20 sx=2 sy=3 sz=2 mat='grass_01')
(cylinder x=0 y=3.15 z=-20 sx=2.4 sy=0.3 sz=2.4 mat='grass_01')

# === Pipe 3 — tall ===
(cylinder x=0 y=2 z=-15 sx=2 sy=4 sz=2 mat='grass_01')
(cylinder x=0 y=4.15 z=-15 sx=2.4 sy=0.3 sz=2.4 mat='grass_01')


# === Floating brick platform between pits (mid-air ledge to jump up to) ===
(box x=-2.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-1.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-0.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='sand_01')
(box x=0.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='brick_02')
(box x=1.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='sand_01')
(box x=2.5 y=3 z=-6 sx=1 sy=1 sz=1 mat='brick_02')


# === Two-tier coin-block formation ===
# Upper ceiling row (4 bricks)
(box x=-1.5 y=6 z=2 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-0.5 y=6 z=2 sx=1 sy=1 sz=1 mat='brick_02')
(box x=0.5 y=6 z=2 sx=1 sy=1 sz=1 mat='brick_02')
(box x=1.5 y=6 z=2 sx=1 sy=1 sz=1 mat='brick_02')
# Lower row (mixed with ? blocks)
(box x=-1.5 y=3 z=2 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-0.5 y=3 z=2 sx=1 sy=1 sz=1 mat='sand_01')
(box x=0.5 y=3 z=2 sx=1 sy=1 sz=1 mat='sand_01')
(box x=1.5 y=3 z=2 sx=1 sy=1 sz=1 mat='brick_02')


# === Tall pipe right before pit 2 ===
(cylinder x=0 y=2.5 z=9 sx=2 sy=5 sz=2 mat='grass_01')
(cylinder x=0 y=5.15 z=9 sx=2.4 sy=0.3 sz=2.4 mat='grass_01')


# === Brick cluster after pit 2 ===
(box x=-1.5 y=3 z=22 sx=1 sy=1 sz=1 mat='brick_02')
(box x=-0.5 y=3 z=22 sx=1 sy=1 sz=1 mat='brick_02')
(box x=0.5 y=3 z=22 sx=1 sy=1 sz=1 mat='sand_01')
(box x=1.5 y=3 z=22 sx=1 sy=1 sz=1 mat='brick_02')

# Floating coins (yellow spheres above the row)
(sphere x=-1.5 y=5 z=22 sx=0.4 sy=0.4 sz=0.4 mat='sand_01')
(sphere x=-0.5 y=5 z=22 sx=0.4 sy=0.4 sz=0.4 mat='sand_01')
(sphere x=0.5 y=5 z=22 sx=0.4 sy=0.4 sz=0.4 mat='sand_01')
(sphere x=1.5 y=5 z=22 sx=0.4 sy=0.4 sz=0.4 mat='sand_01')

# === Staircase — 4 stepped columns rising 1 block each ===
# (built as horizontal slabs running east-west, each step 1m taller than the last)
# Step 1 (1 block tall)
(box x=0 y=0.5 z=27 sx=4 sy=1 sz=1 mat='brick_03')
# Step 2 (2 blocks tall)
(box x=0 y=1 z=28 sx=4 sy=2 sz=1 mat='brick_03')
# Step 3 (3 blocks tall)
(box x=0 y=1.5 z=29 sx=4 sy=3 sz=1 mat='brick_03')
# Step 4 (4 blocks tall) — top of the staircase
(box x=0 y=2 z=30 sx=4 sy=4 sz=1 mat='brick_03')

# Matching descending staircase on the other side of pit 3 (for symmetry)
(box x=0 y=2 z=39 sx=4 sy=4 sz=1 mat='brick_03')
(box x=0 y=1.5 z=40 sx=4 sy=3 sz=1 mat='brick_03')
(box x=0 y=1 z=41 sx=4 sy=2 sz=1 mat='brick_03')
(box x=0 y=0.5 z=42 sx=4 sy=1 sz=1 mat='brick_03')

# === Flagpole ===
# Square stone base
(box x=0 y=0.75 z=46 sx=2 sy=1.5 sz=2 mat='concrete_03')
# Pole
(cylinder x=0 y=6 z=46 sx=0.2 sy=11 sz=0.2 mat='metal_01')
# Ball on top
(sphere x=0 y=11.7 z=46 sx=0.5 sy=0.5 sz=0.5 mat='metal_02')
# Flag (a small banner on the pole)
(box x=-0.7 y=9.8 z=46 sx=1.4 sy=1 sz=0.05 mat='brick_02')

# === End-of-level castle (Bowser's keep) ===
# Main body
(box x=0 y=3 z=54 sx=10 sy=6 sz=6 mat='brick_03')
# Crenellations along the roof (4 little blocks for the toothy castle silhouette)
(box x=-4 y=6.5 z=54 sx=1 sy=1 sz=6 mat='brick_03')
(box x=-1.5 y=6.5 z=54 sx=1 sy=1 sz=6 mat='brick_03')
(box x=1.5 y=6.5 z=54 sx=1 sy=1 sz=6 mat='brick_03')
(box x=4 y=6.5 z=54 sx=1 sy=1 sz=6 mat='brick_03')
# Central tower
(box x=0 y=7.5 z=54 sx=3 sy=3 sz=3 mat='brick_03')
# Tower crenellations
(box x=-1.25 y=9.5 z=54 sx=0.5 sy=1 sz=3 mat='brick_03')
(box x=0 y=9.5 z=54 sx=0.5 sy=1 sz=3 mat='brick_03')
(box x=1.25 y=9.5 z=54 sx=0.5 sy=1 sz=3 mat='brick_03')
# Carve out the castle archway entrance
(sub (box x=0 y=1.4 z=51 sx=2.2 sy=3 sz=1.5 mat='brick_03'))
# Dark wooden door inside the archway
(box x=0 y=1.3 z=51.1 sx=2 sy=2.6 sz=0.1 mat='wood_04')
# Round window above the door
(sphere x=0 y=4.5 z=51 sx=1.2 sy=1.2 sz=0.4 mat='wood_04')

